import math, random

def reparameterise(mu, log_var):
    """
    Reparameterisation trick: z = mu + std * epsilon, epsilon ~ N(0,1).
    mu, log_var: lists of floats (latent dimension d)
    Returns z (list of floats).
    """
    return [
        mu[i] + math.exp(0.5 * log_var[i]) * ___________
        for i in range(len(mu))
    ]

def kl_divergence(mu, log_var):
    """
    Analytical KL(N(mu,sigma^2) || N(0,1)) per dimension, summed.
    KL = -0.5 * sum(1 + log_var - mu^2 - exp(log_var))
    """
    return -0.5 * sum(1 + log_var[i] - mu[i]**2 - math.exp(log_var[i])
                      for i in range(len(mu)))

def vae_loss(x, x_recon, mu, log_var):
    """ELBO = reconstruction (MSE) + KL."""
    recon = sum((x[i]-x_recon[i])**2 for i in range(len(x)))
    return recon + kl_divergence(mu, log_var)
